var body = $input.first().json.body || {};
var endpoints = body.endpoints || [];
var qualityThreshold = body.qualityThreshold || 70;

if (!endpoints.length) {
  throw new Error('No endpoints array in POST body');
}
if (endpoints.length > 5) {
  throw new Error('Maximum 5 endpoints allowed');
}

return [{ json: { endpoints: endpoints, qualityThreshold: qualityThreshold, requestedAt: $now.toISO() } }];

var data = $input.first().json;
return data.endpoints.map(function(ep, idx) {
  return { json: { url: ep.url, expectedFields: ep.expectedFields || [], index: idx, qualityThreshold: data.qualityThreshold, totalEndpoints: data.endpoints.length } };
});

var items = $input.all();
var origItems = $('Split Endpoints').all();

return items.map(function(item, idx) {
  var orig = origItems[idx] ? origItems[idx].json : {};
  var url = orig.url || 'unknown';
  var expectedFields = orig.expectedFields || [];
  var error = item.json.error;

  if (error) {
    var msg = typeof error === 'object' ? (error.message || JSON.stringify(error)) : String(error);
    return { json: { url: url, status: 'error', error: msg, records: [], recordCount: 0, expectedFields: expectedFields, qualityThreshold: orig.qualityThreshold, totalEndpoints: orig.totalEndpoints } };
  }

  var rawData = item.json.data || item.json.text || '';
  var records = [];
  try {
    var parsed = JSON.parse(rawData);
    if (Array.isArray(parsed)) {
      records = parsed.slice(0, 20);
    } else if (parsed && typeof parsed === 'object') {
      records = [parsed];
    }
  } catch(e) {
    records = [{ rawText: String(rawData).substring(0, 200) }];
  }

  return { json: { url: url, status: 'ok', records: records, recordCount: records.length, expectedFields: expectedFields, qualityThreshold: orig.qualityThreshold, totalEndpoints: orig.totalEndpoints } };
});

var items = $input.all();

return items.map(function(item) {
  var j = item.json;
  if (j.status === 'error') {
    return { json: Object.assign({}, j, { qualityScore: 0 }) };
  }

  var records = j.records || [];
  var expected = j.expectedFields || [];
  var totalChecks = 0;
  var passedChecks = 0;

  for (var r = 0; r < records.length; r++) {
    var record = records[r];
    for (var f = 0; f < expected.length; f++) {
      totalChecks++;
      if (record[expected[f]] !== undefined && record[expected[f]] !== null && record[expected[f]] !== '') {
        passedChecks++;
      }
    }
  }

  var qualityScore = totalChecks > 0 ? Math.round((passedChecks / totalChecks) * 100) : 0;
  return { json: Object.assign({}, j, { qualityScore: qualityScore, totalChecks: totalChecks, passedChecks: passedChecks }) };
});

var items = $input.all();
var seen = {};

return items.map(function(item) {
  var j = item.json;
  if (j.status === 'error') return item;

  var records = j.records || [];
  var deduped = [];
  var dupsRemoved = 0;

  for (var i = 0; i < records.length; i++) {
    var key = JSON.stringify(records[i]);
    if (!seen[key]) {
      seen[key] = true;
      deduped.push(records[i]);
    } else {
      dupsRemoved++;
    }
  }

  return { json: Object.assign({}, j, { records: deduped, recordCount: deduped.length, duplicatesRemoved: dupsRemoved }) };
});

var items = $input.all();
var totalRecords = 0;
var totalErrors = 0;
var totalDups = 0;
var sources = [];
var avgQuality = 0;
var qualitySum = 0;
var qualityCount = 0;
var threshold = items[0] ? items[0].json.qualityThreshold : 70;

for (var i = 0; i < items.length; i++) {
  var j = items[i].json;
  if (j.status === 'error') {
    totalErrors++;
    sources.push({ url: j.url, status: 'error', error: j.error });
  } else {
    totalRecords += j.recordCount;
    totalDups += (j.duplicatesRemoved || 0);
    qualitySum += j.qualityScore;
    qualityCount++;
    sources.push({ url: j.url, status: 'ok', recordCount: j.recordCount, qualityScore: j.qualityScore, duplicatesRemoved: j.duplicatesRemoved || 0 });
  }
}

avgQuality = qualityCount > 0 ? Math.round(qualitySum / qualityCount) : 0;

var qualityLevel = 'good';
if (totalErrors > 0 || avgQuality < threshold * 0.5) {
  qualityLevel = 'critical';
} else if (avgQuality < threshold) {
  qualityLevel = 'degraded';
}

var hasData = totalRecords > 0 || totalErrors > 0;

return [{ json: { totalSources: items.length, totalRecords: totalRecords, totalErrors: totalErrors, totalDuplicates: totalDups, avgQuality: avgQuality, qualityLevel: qualityLevel, qualityThreshold: threshold, sources: sources, hasData: hasData } }];

var j = $input.first().json;
var NL = String.fromCharCode(10);
var lines = [];
lines.push('**Data Pipeline Validation Report**');
lines.push('Sources: ' + j.totalSources + ' | Records: ' + j.totalRecords + ' | Errors: ' + j.totalErrors + ' | Dups removed: ' + j.totalDuplicates);
lines.push('Avg Quality: ' + j.avgQuality + '% (threshold: ' + j.qualityThreshold + '%)');
lines.push('Status: **' + j.qualityLevel.toUpperCase() + '**');
lines.push('');

var sources = j.sources || [];
for (var i = 0; i < sources.length; i++) {
  var s = sources[i];
  if (s.status === 'error') {
    lines.push('\u274c ' + s.url + ': ERROR - ' + s.error);
  } else {
    var icon = s.qualityScore >= j.qualityThreshold ? '\u2705' : '\u26a0\ufe0f';
    lines.push(icon + ' ' + s.url + ': ' + s.recordCount + ' records, quality ' + s.qualityScore + '%' + (s.duplicatesRemoved > 0 ? ' (' + s.duplicatesRemoved + ' dups)' : ''));
  }
}

return [{ json: { report: lines.join(NL), qualityLevel: j.qualityLevel, avgQuality: j.avgQuality, totalErrors: j.totalErrors } }];
